#!/usr/bin/env python3
# ADT Framework Bootstrap
# Generated from OceanPulse Phase One
#
# Usage: python3 adt_bootstrap.py
# This will hydrate the _cortex/, ops/, and adt_panel/ structures.

import os
import sys
import base64
from pathlib import Path

def write_file(path, content_b64):
    p = Path(path)
    p.parent.mkdir(parents=True, exist_ok=True)
    with open(p, "wb") as f:
        f.write(base64.b64decode(content_b64))
    print(f"✅ Created: {path}")
    
    # Make scripts executable
    if path.endswith(".sh") or path.endswith(".py"):
        os.chmod(path, 0o755)

def main():
    print("=== Hydrating ADT Framework ===")
    
    # Creates empty critical dirs
    dirs = [
        "_cortex/ads",
        "_cortex/specs", 
        "_cortex/work_logs",
        "_cortex/active_tasks"
    ]
    for d in dirs:
        Path(d).mkdir(parents=True, exist_ok=True)
        print(f"✅ Directory: {d}")


    # File Definitions
    write_file("_cortex/ADT_CONSTITUTION.md", "")
    write_file("_cortex/AI_PROTOCOL.md", "")
    write_file("_cortex/AGENTS.md", "")
    write_file("_cortex/ops/log.py", "")
    write_file("_cortex/roles/Overseer/compile_ads.py", "")
    write_file("ops/backup_ads.sh", "")
    write_file("adt_panel/index.html", "")
    write_file("adt_panel/style.css", "")
    write_file("adt_panel/panel.js", "")
    write_file("adt_panel/about.html", "")
    write_file("adt_panel/deploy.sh", "")
    write_file("_cortex/ads/schema.json", "")

    print("\n🎉 ADT Framework Installed Successfully.")
    print("Next Steps:")
    print("1. Review _cortex/ADT_CONSTITUTION.md")
    print("2. Configure adt_panel/deploy.sh with your hosting credentials")
    print("3. Start working! (Logs will go to _cortex/ads/events.jsonl)")

if __name__ == "__main__":
    main()
